INSERT INTO journal_entries (record_id, project, category, content, tags, createdat, local_project_id) VALUES
('d1tp1_journal_001', 'recgdpwEI5hF07bUZ', 'perceptions', 'The team is beginning to see research evidence as an operating model rather than a set of documents. People trust findings more when they can see where an observation came from, what is still uncertain and which decision it was meant to support.', '["evidence-readiness","confidence","decision-support"]', '2026-06-03T09:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_002', 'recgdpwEI5hF07bUZ', 'procedures', 'The weekly intake meeting now checks every new research request for the decision it supports, the evidence already available, the recruitment route and any delivery deadline before work is accepted.', '["triage","request-intake","planning"]', '2026-06-03T14:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_003', 'recgdpwEI5hF07bUZ', 'decisions', 'We decided to keep operations tracking separate from qualitative synthesis. Recruitment status and scheduling need to stay visible, but coding and memo writing should remain in the analysis space with links back to decisions.', '["decision-trace","operations","synthesis"]', '2026-06-04T10:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_004', 'recgdpwEI5hF07bUZ', 'introspections', 'The strongest value of the platform may be that it slows down the right decisions while making routine research administration easier to manage. That slower pace is uncomfortable, but it is also where the quality improves.', '["reflection","governance","decision-quality"]', '2026-06-04T16:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_005', 'recgdpwEI5hF07bUZ', 'procedures', 'Recruitment planning exposed a gap between the participant access needs recorded by delivery teams and the practical adjustments researchers need before a session. We added a check for access needs before diary invitations are sent.', '["recruitment","access-needs","participant-support"]', '2026-06-05T09:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_006', 'recgdpwEI5hF07bUZ', 'perceptions', 'Several researchers described losing the thread when they moved between the project dashboard, notes, spreadsheets and mural boards. The issue is not only tool count; it is the mental effort of rebuilding context every time.', '["context-rebuilding","tool-switching","researcher-workload"]', '2026-06-05T13:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_007', 'recgdpwEI5hF07bUZ', 'introspections', 'I noticed that I was treating missing provenance as a delivery inconvenience rather than an analytical risk. If we cannot tell who contributed an insight or when it was last reviewed, we should lower our confidence in decisions that depend on it.', '["provenance","positionality","confidence"]', '2026-06-06T11:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_008', 'recgdpwEI5hF07bUZ', 'decisions', 'The team agreed that high-risk service decisions need an evidence handover note before they move to implementation. The note should capture the decision, supporting findings, known gaps and the researcher confidence level.', '["handover","decision-rationale","confidence-threshold"]', '2026-06-06T15:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_009', 'recgdpwEI5hF07bUZ', 'procedures', 'We added a short pause before contacting participants whose circumstances may make participation burdensome. The pause gives the researcher time to review consent wording, support options and whether the invitation should be delayed.', '["consent","ethical-pacing","participant-burden"]', '2026-06-07T10:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_010', 'recgdpwEI5hF07bUZ', 'perceptions', 'The dashboard is useful when it shows what changed since the last visit. Researchers do not need another place to duplicate updates; they need a way to re-enter the project without reading every artefact again.', '["duplicate-updates","context-rebuilding","dashboard"]', '2026-06-07T14:55:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_011', 'recgdpwEI5hF07bUZ', 'introspections', 'The emotional labour of holding uncertainty for a project team is becoming more visible. Researchers are being asked for certainty before the evidence is ready, and the platform needs to legitimise saying that confidence is not yet high enough.', '["emotional-labour","uncertainty","confidence-threshold"]', '2026-06-08T09:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_012', 'recgdpwEI5hF07bUZ', 'decisions', 'We agreed to show code co-occurrence as a prompt for interpretation, not as proof of a relationship. The graph should help researchers notice patterns, then return to journal entries and memos to check the meaning.', '["co-occurrence","analysis-practice","interpretation"]', '2026-06-08T16:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_013', 'recgdpwEI5hF07bUZ', 'perceptions', 'Researchers are asking for a clearer distinction between an observation, an interpretation and a theme. The current language is familiar to analysts, but less clear to delivery colleagues who read the codebook later.', '["code-hierarchy","shared-language","interpretation"]', '2026-06-09T09:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_014', 'recgdpwEI5hF07bUZ', 'procedures', 'The research team added a short evidence review before every show-and-tell. The review checks whether quoted findings still have a source, whether the finding has been challenged and whether a memo records the interpretation.', '["evidence-review","show-and-tell","memo-practice"]', '2026-06-09T13:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_015', 'recgdpwEI5hF07bUZ', 'introspections', 'I found myself defending a pattern because it supported a design idea I already preferred. The negative case in yesterday''s interview helped me separate the participant''s account from my own product instinct.', '["negative-case","positionality","analysis-confidence"]', '2026-06-10T10:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_016', 'recgdpwEI5hF07bUZ', 'decisions', 'We agreed that code co-occurrence should be shown as a ranked table first. A visual graph can follow, but the first need is to see which code pairs are repeated often enough to warrant closer reading.', '["co-occurrence","ranked-table","analysis-tooling"]', '2026-06-10T15:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_017', 'recgdpwEI5hF07bUZ', 'procedures', 'Consent wording is being checked earlier in recruitment planning. The change has reduced late rework because accessibility needs, support options and participant burden are visible before invitations are drafted.', '["consent","accessibility","recruitment"]', '2026-06-11T09:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_018', 'recgdpwEI5hF07bUZ', 'perceptions', 'Delivery leads value the journal when it explains why research has slowed a decision. The entry needs to say what risk is being reduced, not only that more evidence is needed.', '["decision-delay","risk-threshold","delivery"]', '2026-06-11T14:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_019', 'recgdpwEI5hF07bUZ', 'introspections', 'The codebook is starting to reveal where I have over-coded process details and under-coded emotional labour. I need to revisit entries where uncertainty was held by researchers but described only as governance delay.', '["codebook-review","emotional-labour","governance"]', '2026-06-12T09:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_020', 'recgdpwEI5hF07bUZ', 'decisions', 'We will keep first-order codes close to the language of the entry, second-order codes for interpretation and thematic codes for aggregate themes. The UI should show this hierarchy without requiring users to infer it from indentation.', '["code-hierarchy","ui-clarity","analysis-practice"]', '2026-06-12T12:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_021', 'recgdpwEI5hF07bUZ', 'procedures', 'Participant support options now get recorded alongside recruitment constraints. This makes it easier to decide whether a study can proceed responsibly or whether the team needs to pause.', '["participant-support","recruitment","ethical-pacing"]', '2026-06-12T16:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_022', 'recgdpwEI5hF07bUZ', 'perceptions', 'Teams are more willing to trust a finding when the journal links it to a memo, a decision and a dated review. The last reviewed date is becoming a proxy for whether evidence is still usable.', '["last-reviewed","traceability","trust"]', '2026-06-13T10:55:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_023', 'recgdpwEI5hF07bUZ', 'introspections', 'I am using follow-up questions as a way to hold uncertainty rather than forcing a premature theme. The codebook should make unfinished interpretation visible without making it look like failure.', '["follow-up-question","uncertainty","theme-development"]', '2026-06-13T15:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_024', 'recgdpwEI5hF07bUZ', 'decisions', 'The team decided to review co-occurring codes weekly. Repeated pairs will prompt a memo only when the underlying excerpts show a meaningful relationship rather than repeated administrative wording.', '["co-occurrence","memo-trigger","weekly-review"]', '2026-06-14T11:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_025', 'recgdpwEI5hF07bUZ', 'procedures', 'Approval delays are now recorded with the reason for the delay and the evidence needed to move forward. This has helped separate governance tempo from avoidable handover gaps.', '["approval-delay","governance-tempo","handover"]', '2026-06-14T16:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_026', 'recgdpwEI5hF07bUZ', 'perceptions', 'Researchers said they want the analysis area to feel like a working space rather than a reporting tool. They need to see patterns, unfinished questions and supporting excerpts in the same flow.', '["analysis-space","working-practice","supporting-excerpts"]', '2026-06-15T09:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_027', 'recgdpwEI5hF07bUZ', 'introspections', 'The strongest memos are the ones that name uncertainty clearly. They do not pretend that a pattern is settled; they explain what would make the interpretation stronger.', '["memo-quality","uncertainty","analysis-confidence"]', '2026-06-15T14:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_028', 'recgdpwEI5hF07bUZ', 'decisions', 'We agreed that every aggregate theme should have at least two second-order codes beneath it before it is used in reporting. This should reduce shallow themes that only rename a single observation.', '["theme-quality","second-order-codes","reporting"]', '2026-06-16T10:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_029', 'recgdpwEI5hF07bUZ', 'procedures', 'Session adjustments are easier to plan when access needs are visible before recruitment begins. The operational check is now linked to the ethical pacing memo rather than sitting in a separate delivery note.', '["session-adjustments","access-needs","ethical-pacing"]', '2026-06-16T15:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_030', 'recgdpwEI5hF07bUZ', 'perceptions', 'People are starting to use the journal to explain trade-offs. The most useful entries state what was gained, what was delayed and what evidence would change the decision.', '["trade-offs","decision-rationale","evidence-change"]', '2026-06-17T09:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_031', 'recgdpwEI5hF07bUZ', 'introspections', 'The difference between a repeated pattern and a compelling theme is becoming clearer. A theme needs interpretive work, not just a count of similar excerpts.', '["theme-development","interpretation","pattern-count"]', '2026-06-17T13:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_032', 'recgdpwEI5hF07bUZ', 'decisions', 'We will use the co-occurrence table to pick review candidates, not to automate conclusions. The table should help researchers choose where to read, compare and write memos.', '["co-occurrence","review-candidates","memo-writing"]', '2026-06-18T10:00:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_033', 'recgdpwEI5hF07bUZ', 'procedures', 'Shared interpretation sessions now start with two excerpts that appear to contradict the emerging theme. This has made the discussion slower but more grounded.', '["shared-interpretation","negative-case","theme-review"]', '2026-06-18T15:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_034', 'recgdpwEI5hF07bUZ', 'perceptions', 'The platform is most helpful when it shows provenance without making researchers behave like data clerks. The provenance fields need to support judgement rather than become another compliance burden.', '["provenance","researcher-workload","governance"]', '2026-06-19T09:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_035', 'recgdpwEI5hF07bUZ', 'introspections', 'I need to separate my concern about delivery pressure from the evidence itself. The journal helps because it gives me somewhere to name the pressure before writing the analytical memo.', '["delivery-pressure","positionality","memo-practice"]', '2026-06-19T14:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_036', 'recgdpwEI5hF07bUZ', 'decisions', 'The next review will compare evidence readiness with inclusive engagement. We need to see whether accessibility constraints are being treated as operational blockers or as evidence about how the service works for people.', '["inclusive-engagement","evidence-readiness","accessibility"]', '2026-06-20T11:00:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2')
