('d1tp1_code_traceable_decisions', 'recgdpwEI5hF07bUZ', 'Traceable decisions', 'Interpretive code for linking choices to evidence, uncertainty and rationale.', 'd1tp1_code_theme_evidence_readiness', '#2b8cc4ff', '2026-06-03T10:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_traceable_decisions'),
('d1tp1_code_decision_rationale', 'recgdpwEI5hF07bUZ', 'Decision rationale', 'Descriptive code for the stated reason behind a product or research decision.', 'd1tp1_code_traceable_decisions', '#2b8cc4ff', '2026-06-03T10:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_decision_rationale'),
('d1tp1_code_evidence_handover', 'recgdpwEI5hF07bUZ', 'Evidence handover', 'Descriptive code for packaging findings, gaps and confidence for a decision owner.', 'd1tp1_code_traceable_decisions', '#2b8cc4ff', '2026-06-03T10:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_evidence_handover'),
('d1tp1_code_theme_operational_rhythm', 'recgdpwEI5hF07bUZ', 'Operational rhythm', 'Aggregate theme for the routines and coordination that make research work manageable.', '', '#00703cff', '2026-06-03T10:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_theme_operational_rhythm'),
('d1tp1_code_triage_discipline', 'recgdpwEI5hF07bUZ', 'Triage discipline', 'Interpretive code for the rules and judgement used to accept, sequence or defer work.', 'd1tp1_code_theme_operational_rhythm', '#00703cff', '2026-06-03T10:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_triage_discipline'),
('d1tp1_code_request_intake', 'recgdpwEI5hF07bUZ', 'Request intake', 'Descriptive code for how incoming research requests are captured and assessed.', 'd1tp1_code_triage_discipline', '#00703cff', '2026-06-03T10:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_request_intake'),
('d1tp1_code_recruitment_constraints', 'recgdpwEI5hF07bUZ', 'Recruitment constraints', 'Descriptive code for limits that shape who can be involved and when sessions can happen.', 'd1tp1_code_triage_discipline', '#00703cff', '2026-06-03T10:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_recruitment_constraints'),
('d1tp1_code_tool_switching_burden', 'recgdpwEI5hF07bUZ', 'Tool-switching burden', 'Interpretive code for friction caused by moving between tools and rebuilding context.', 'd1tp1_code_theme_operational_rhythm', '#28a197ff', '2026-06-03T10:55:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_tool_switching_burden'),
('d1tp1_code_duplicate_updates', 'recgdpwEI5hF07bUZ', 'Duplicate updates', 'Descriptive code for repeated status updates across multiple locations.', 'd1tp1_code_tool_switching_burden', '#28a197ff', '2026-06-03T11:00:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_duplicate_updates'),
('d1tp1_code_context_rebuilding', 'recgdpwEI5hF07bUZ', 'Context rebuilding', 'Descriptive code for the effort needed to recover project state after switching tools or time away.', 'd1tp1_code_tool_switching_burden', '#28a197ff', '2026-06-03T11:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_context_rebuilding'),
('d1tp1_code_theme_reflexive_practice', 'recgdpwEI5hF07bUZ', 'Reflexive practice', 'Aggregate theme for researcher judgement, positionality and ethical pacing.', '', '#4c2c92ff', '2026-06-03T11:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_theme_reflexive_practice'),
('d1tp1_code_researcher_positionality', 'recgdpwEI5hF07bUZ', 'Researcher positionality', 'Interpretive code for how researcher assumptions and responsibilities shape analysis.', 'd1tp1_code_theme_reflexive_practice', '#4c2c92ff', '2026-06-03T11:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_researcher_positionality'),
('d1tp1_code_assumption_surfaced', 'recgdpwEI5hF07bUZ', 'Assumption surfaced', 'Descriptive code for moments where a researcher recognises and records an assumption.', 'd1tp1_code_researcher_positionality', '#4c2c92ff', '2026-06-03T11:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_assumption_surfaced'),
('d1tp1_code_emotional_labour', 'recgdpwEI5hF07bUZ', 'Emotional labour', 'Descriptive code for the personal effort of holding uncertainty, risk or tension in the work.', 'd1tp1_code_researcher_positionality', '#4c2c92ff', '2026-06-03T11:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_emotional_labour'),
('d1tp1_code_ethical_pacing', 'recgdpwEI5hF07bUZ', 'Ethical pacing', 'Interpretive code for deliberately slowing activity to protect participants or improve judgement.', 'd1tp1_code_theme_reflexive_practice', '#6f72afff', '2026-06-03T11:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_ethical_pacing'),
('d1tp1_code_pause_for_consent', 'recgdpwEI5hF07bUZ', 'Pause for consent', 'Descriptive code for stopping to review consent, burden or support before contacting participants.', 'd1tp1_code_ethical_pacing', '#6f72afff', '2026-06-03T11:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_pause_for_consent'),
('d1tp1_code_decision_slowed', 'recgdpwEI5hF07bUZ', 'Decision slowed', 'Descriptive code for deliberately delaying a decision until evidence or consent is stronger.', 'd1tp1_code_ethical_pacing', '#6f72afff', '2026-06-03T11:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_decision_slowed'),
('d1tp1_code_theme_inclusive_engagement', 'recgdpwEI5hF07bUZ', 'Inclusive engagement', 'Aggregate theme for making participation practical, ethical and accessible.', '', '#d4351cff', '2026-06-03T11:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_theme_inclusive_engagement'),
('d1tp1_code_participant_burden', 'recgdpwEI5hF07bUZ', 'Participant burden', 'Interpretive code for recognising when participation may be too demanding or poorly timed.', 'd1tp1_code_theme_inclusive_engagement', '#d4351cff', '2026-06-03T11:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_participant_burden'),
('d1tp1_code_consent_wording_review', 'recgdpwEI5hF07bUZ', 'Consent wording review', 'Descriptive code for checking whether consent language is clear, proportionate and usable.', 'd1tp1_code_participant_burden', '#d4351cff', '2026-06-03T11:55:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_consent_wording_review'),
('d1tp1_code_support_options', 'recgdpwEI5hF07bUZ', 'Support options', 'Descriptive code for practical support offered before, during or after research.', 'd1tp1_code_participant_burden', '#d4351cff', '2026-06-03T12:00:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_support_options'),
('d1tp1_code_access_adjustment', 'recgdpwEI5hF07bUZ', 'Access adjustment', 'Interpretive code for adapting recruitment or sessions to meet access needs.', 'd1tp1_code_theme_inclusive_engagement', '#f47738ff', '2026-06-03T12:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_access_adjustment'),
('d1tp1_code_access_needs', 'recgdpwEI5hF07bUZ', 'Access needs', 'Descriptive code for recorded participant access needs.', 'd1tp1_code_access_adjustment', '#f47738ff', '2026-06-03T12:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_access_needs'),
('d1tp1_code_session_adjustments', 'recgdpwEI5hF07bUZ', 'Session adjustments', 'Descriptive code for changes made to session format, timing or support.', 'd1tp1_code_access_adjustment', '#f47738ff', '2026-06-03T12:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_session_adjustments'),
