('d1tp1_code_analysis_confidence', 'recgdpwEI5hF07bUZ', 'Analysis confidence', 'Interpretive code for how strongly an interpretation is supported by excerpts and memos.', 'd1tp1_code_theme_reflexive_practice', '#912b88ff', '2026-06-03T12:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_code_analysis_confidence'),
