INSERT INTO memos (record_id, project, type, title, body, createdat, local_project_id, local_memo_id) VALUES
('d1tp1_memo_001', 'recgdpwEI5hF07bUZ', 'analytical', 'Evidence readiness is the organising problem', 'The journal entries show that evidence quality is not only about producing findings. Confidence depends on provenance, explicit uncertainty and a handover that connects findings to the decision being made.', '2026-06-04T12:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_001'),
('d1tp1_memo_002', 'recgdpwEI5hF07bUZ', 'methodological', 'Separate operations tracking from synthesis', 'Recruitment status, scheduling and request intake belong in operational tracking. Codes, memos and journal entries belong in analysis. The product should make the relationship visible without merging the activities.', '2026-06-05T10:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_002'),
('d1tp1_memo_003', 'recgdpwEI5hF07bUZ', 'analytical', 'Context rebuilding is a hidden cost', 'Tool switching appears repeatedly with duplicate updates and loss of project state. The strongest design response may be surfacing what changed since the researcher last worked on the project.', '2026-06-06T13:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_003'),
('d1tp1_memo_004', 'recgdpwEI5hF07bUZ', 'reflexive', 'Researcher confidence needs permission to be low', 'The entries about uncertainty and emotional labour suggest that researchers need a legitimate way to say evidence is not ready. The platform should support careful delay, not only faster throughput.', '2026-06-07T11:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_004'),
('d1tp1_memo_005', 'recgdpwEI5hF07bUZ', 'analytical', 'Co-occurrence should prompt interpretation', 'The co-occurrence graph is useful when it reveals repeated pairings such as confidence threshold with decision slowed, or context rebuilding with duplicate updates. It should send researchers back to the underlying entries rather than imply causal proof.', '2026-06-08T17:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_005'),
('d1tp1_memo_006', 'recgdpwEI5hF07bUZ', 'methodological', 'Use the code hierarchy as an analytic scaffold', 'First-order codes should stay close to what was recorded, second-order codes should capture the researcher''s interpretation, and thematic codes should aggregate patterns that have been checked against memos.', '2026-06-10T11:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_006'),
('d1tp1_memo_007', 'recgdpwEI5hF07bUZ', 'analytical', 'Inclusive engagement changes the evidence', 'Access needs and support options are not only operational constraints. They shape who can participate, what evidence is available and whether findings can be trusted across user groups.', '2026-06-11T16:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_007'),
('d1tp1_memo_008', 'recgdpwEI5hF07bUZ', 'reflexive', 'Negative cases are protecting the analysis', 'The negative case examples are stopping early closure. They help distinguish repeated observations from themes that have been interpreted and challenged.', '2026-06-13T16:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_008'),
('d1tp1_memo_009', 'recgdpwEI5hF07bUZ', 'analytical', 'Governance tempo is not the same as delay', 'Approval delay matters when it hides what evidence is needed. Governance tempo is productive when it names risk thresholds and helps teams decide what would make a decision ready.', '2026-06-14T17:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_009'),
('d1tp1_memo_010', 'recgdpwEI5hF07bUZ', 'methodological', 'Co-occurrence review cadence', 'Weekly review of repeated code pairs should start with the highest-weight pairs, then inspect excerpts and decide whether a memo is warranted. Counts alone should not be treated as evidence.', '2026-06-16T11:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_010'),
('d1tp1_memo_011', 'recgdpwEI5hF07bUZ', 'reflexive', 'Delivery pressure needs a place in the journal', 'Naming delivery pressure before writing an analytical memo helps separate project urgency from evidence strength. This protects analysis confidence.', '2026-06-19T15:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_011'),
('d1tp1_memo_012', 'recgdpwEI5hF07bUZ', 'analytical', 'Evidence readiness and inclusive engagement overlap', 'The strongest current co-occurrence to review is between evidence readiness and inclusive engagement. Accessibility constraints are being treated both as operational blockers and as evidence about service fit.', '2026-06-20T12:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2', 'd1tp1_memo_012')
